define('taoQtiTest/runner/plugins/controls/testState/testState',['lodash', 'taoTests/runner/plugin'], function (_, pluginFactory) {
  'use strict';

  _ = _ && Object.prototype.hasOwnProperty.call(_, 'default') ? _['default'] : _;
  pluginFactory = pluginFactory && Object.prototype.hasOwnProperty.call(pluginFactory, 'default') ? pluginFactory['default'] : pluginFactory;
  var testState = pluginFactory({
    name: 'testState',
    install: function install() {
      var testRunner = this.getTestRunner();
      testRunner.getProxy().use(function qtiFilter(req, res, next) {
        var data = res && res.data;
        if (data && data.type && data.type === 'TestState' && !testRunner.getState('closedOrSuspended')) {
          testRunner.setState('closedOrSuspended', true);
          if (!testRunner.getState('ready')) {
            testRunner.trigger('destroy');
          } else if (_.isEmpty(data.messages) || !_.find(data.messages, {
            channel: 'teststate'
          })) {
            testRunner.trigger('leave', data);
          }
          return;
        }
        next();
      });
    },
    init: function init() {
      var testRunner = this.getTestRunner();
      var isLeaving = false;
      testRunner.getProxy().channel('teststate', function (data) {
        if (!isLeaving && data && ('close' === data.type || 'pause' === data.type) && !testRunner.getState('closedOrSuspended')) {
          isLeaving = true;
          if ('pause' === data.type) {
            testRunner.trigger('pause', data);
          } else {
            testRunner.setState('closedOrSuspended', true);
            testRunner.trigger('leave', data);
          }
        }
      });
    }
  });
  return testState;
});
