define('taoQtiTest/runner/services/sequenceStore',['core/store'], function (store) {
  'use strict';

  store = store && Object.prototype.hasOwnProperty.call(store, 'default') ? store['default'] : store;
  var STORE_ID = 'current';
  var SEQUENCE_NUMBER = 'sequence';
  var sequenceStore = {
    getSequenceStore() {
      return store(STORE_ID).then(sequenceStore => ({
        setSequenceNumber(sequenceNumber) {
          return sequenceStore.setItem(SEQUENCE_NUMBER, sequenceNumber);
        },
        getSequenceNumber() {
          return sequenceStore.getItem(SEQUENCE_NUMBER);
        }
      }));
    },
    getSequenceNumber(testRunner) {
      return testRunner.getTestStore().getStorageIdentifier().then(storeId => "".concat(storeId, "-").concat(Date.now()));
    }
  };
  return sequenceStore;
});
