define('taoQtiTest/runner/plugins/content/accessibility/keyNavigation/strategies/linearItemNavigation',['jquery', 'ui/keyNavigation/navigator', 'ui/keyNavigation/navigableDomElement', 'taoQtiTest/runner/plugins/content/accessibility/keyNavigation/helpers'], function ($, keyNavigator, navigableDomElement, helpers) {
  'use strict';

  $ = $ && Object.prototype.hasOwnProperty.call($, 'default') ? $['default'] : $;
  keyNavigator = keyNavigator && Object.prototype.hasOwnProperty.call(keyNavigator, 'default') ? keyNavigator['default'] : keyNavigator;
  navigableDomElement = navigableDomElement && Object.prototype.hasOwnProperty.call(navigableDomElement, 'default') ? navigableDomElement['default'] : navigableDomElement;
  var linearItemNavigation = {
    name: 'linearItem',
    init() {
      var config = this.getConfig();
      var $content = this.getTestRunner().getAreaBroker().getContentArea();
      var $qtiInteractions = $content.find('.key-navigation-focusable,.qti-interaction').filter((i, node) => !$(node).parents('.qti-interaction').length);
      var $qtiChoices = $qtiInteractions.find('.qti-choice');
      var $lastParent = null;
      var list = [];
      var setupListNavigator = () => {
        var navigator = keyNavigator({
          elements: list,
          propagateTab: false
        });
        helpers.setupItemsNavigator(navigator, config);
        this.choicesNavigators.push(navigator);
      };
      this.keyNavigators = [];
      this.choicesNavigators = [];
      $content.find('.key-navigation-focusable').addClass('key-navigation-scrollable');
      $qtiChoices.each((i, el) => {
        var $itemElement = $(el);
        var $parent = $itemElement.parent();
        var choiceNavigator = keyNavigator({
          elements: navigableDomElement.createFromDoms($itemElement),
          group: $itemElement,
          propagateTab: false
        });
        helpers.setupClickableNavigator(choiceNavigator);
        if ($lastParent && !$parent.is($lastParent)) {
          setupListNavigator();
          list = [];
        }
        this.keyNavigators.push(choiceNavigator);
        list.push(choiceNavigator);
        $lastParent = $parent;
      });
      if (list.length) {
        setupListNavigator();
        list = [];
      }
      return this;
    },
    getNavigators() {
      return this.keyNavigators;
    },
    destroy() {
      this.keyNavigators.forEach(navigator => navigator.destroy());
      this.choicesNavigators.forEach(navigator => navigator.destroy());
      this.choicesNavigators = [];
      this.keyNavigators = [];
      return this;
    }
  };
  return linearItemNavigation;
});
