define('taoQtiTest/runner/plugins/content/accessibility/keyNavigation/strategies/topToolbarNavigation',['jquery', 'ui/keyNavigation/navigator', 'ui/keyNavigation/navigableDomElement', 'taoQtiTest/runner/plugins/content/accessibility/keyNavigation/helpers'], function ($, keyNavigator, navigableDomElement, helpers) {
  'use strict';

  $ = $ && Object.prototype.hasOwnProperty.call($, 'default') ? $['default'] : $;
  keyNavigator = keyNavigator && Object.prototype.hasOwnProperty.call(keyNavigator, 'default') ? keyNavigator['default'] : keyNavigator;
  navigableDomElement = navigableDomElement && Object.prototype.hasOwnProperty.call(navigableDomElement, 'default') ? navigableDomElement['default'] : navigableDomElement;
  var groupId = 'top-toolbar';
  var topToolbarNavigation = {
    name: 'top-toolbar',
    init() {
      var config = this.getConfig();
      var $topToolbar = this.getTestRunner().getAreaBroker().getContainer().find('.top-action-bar');
      var $toolbarElements = $topToolbar.find('.timer-toggler');
      var registerTopToolbarNavigator = (id, group, $elements) => {
        var elements = navigableDomElement.createFromDoms($elements);
        if (elements.length) {
          var navigator = keyNavigator({
            id,
            group,
            elements,
            propagateTab: false
          });
          helpers.setupItemsNavigator(navigator, config);
          helpers.setupClickableNavigator(navigator);
          this.keyNavigators.push(navigator);
        }
      };
      this.keyNavigators = [];
      $toolbarElements.each((index, element) => registerTopToolbarNavigator("".concat(groupId, "-").concat(index), $topToolbar, $(element)));
      return this;
    },
    getNavigators() {
      return this.keyNavigators;
    },
    destroy() {
      this.keyNavigators.forEach(navigator => navigator.destroy());
      this.keyNavigators = [];
      return this;
    }
  };
  return topToolbarNavigation;
});
