define('taoQtiTest/runner/plugins/controls/timer/strategy/enforcedStay',[],function () {
  'use strict';
  function enforcedStayStrategy(testRunner, timer) {
    var testPart = testRunner.getCurrentPart();
    if (timer && timer.type === 'min' && timer.scope === 'item' && testPart && testPart.isLinear) {
      return {
        name: 'enforcedStay',
        setUp: function setUp() {
          testRunner.on('enablenav.enforcestay', function () {
            testRunner.trigger('disablenav');
          });
          testRunner.trigger('disablenav');
        },
        complete: function complete() {
          this.tearDown();
          testRunner.trigger('enablenav');
        },
        tearDown: function tearDown() {
          testRunner.off('enablenav.enforcestay');
        }
      };
    }
    return false;
  }
  return enforcedStayStrategy;
});
