define('taoQtiTest/runner/plugins/controls/trace/itemTraceVariables',['lodash', 'moment', 'taoTests/runner/plugin'], function (_, moment, pluginFactory) {
  'use strict';

  _ = _ && Object.prototype.hasOwnProperty.call(_, 'default') ? _['default'] : _;
  moment = moment && Object.prototype.hasOwnProperty.call(moment, 'default') ? moment['default'] : moment;
  pluginFactory = pluginFactory && Object.prototype.hasOwnProperty.call(pluginFactory, 'default') ? pluginFactory['default'] : pluginFactory;
  var precision = 1000;
  function timestamp() {
    return Date.now() / precision;
  }
  var itemTraceVariables = pluginFactory({
    name: 'itemTraceVariables',
    install: function install() {
      this.getTestRunner().getTestStore().setVolatile('trace');
    },
    init: function init() {
      var testRunner = this.getTestRunner();
      var variables = {};
      function onError(err) {
        testRunner.trigger('error', err);
      }
      return testRunner.getPluginStore('trace').then(function (tracesStore) {
        testRunner.after('renderitem enableitem', function () {
          var context = testRunner.getTestContext();
          variables = {
            ITEM_START_TIME_CLIENT: timestamp()
          };
          tracesStore.getItem(context.itemIdentifier).then(function (data) {
            if (data) {
              _.merge(variables, data);
            }
            return tracesStore.setItem(context.itemIdentifier, variables);
          }).catch(onError);
        }).before('move skip exit timeout', function () {
          var context = testRunner.getTestContext();
          variables.ITEM_END_TIME_CLIENT = timestamp();
          variables.ITEM_TIMEZONE = moment().utcOffset(moment().utcOffset()).format('Z');
          return tracesStore.setItem(context.itemIdentifier, variables).catch(onError);
        }).before('unloaditem', function () {
          var context = testRunner.getTestContext();
          return testRunner.getProxy().callItemAction(context.itemIdentifier, 'storeTraceData', {
            traceData: JSON.stringify(variables)
          }, true);
        });
      });
    }
  });
  return itemTraceVariables;
});
