define('taoQtiTest/runner/plugins/controls/timer/strategy/timeout',[],function () {
  'use strict';
  function timeoutStrategy(testRunner, timer) {
    if (timer && timer.type === 'max') {
      return {
        name: 'timeout',
        complete: function complete() {
          if (timer.qtiClassName && timer.source) {
            return testRunner.timeout(timer.qtiClassName, timer.source, timer);
          }
        }
      };
    }
    return false;
  }
  return timeoutStrategy;
});
