define('taoQtiTest/runner/plugins/content/accessibility/keyNavigation/strategies/rubricsNavigation',['jquery', 'ui/keyNavigation/navigator', 'ui/keyNavigation/navigableDomElement', 'taoQtiTest/runner/plugins/content/accessibility/keyNavigation/helpers'], function ($, keyNavigator, navigableDomElement, helpers) {
  'use strict';

  $ = $ && Object.prototype.hasOwnProperty.call($, 'default') ? $['default'] : $;
  keyNavigator = keyNavigator && Object.prototype.hasOwnProperty.call(keyNavigator, 'default') ? keyNavigator['default'] : keyNavigator;
  navigableDomElement = navigableDomElement && Object.prototype.hasOwnProperty.call(navigableDomElement, 'default') ? navigableDomElement['default'] : navigableDomElement;
  var groupId = 'rubric-element-navigation-group';
  var rubricsNavigation = {
    name: 'rubrics',
    init() {
      var config = this.getConfig();
      this.keyNavigators = [];
      this.getTestRunner().getAreaBroker().getContainer().find('.qti-rubricBlock').addClass('key-navigation-scrollable').each((i, el) => {
        var $element = $(el);
        var navigator = keyNavigator({
          id: "".concat(groupId, "-").concat(this.keyNavigators.length),
          elements: navigableDomElement.createFromDoms($element),
          group: $element,
          propagateTab: false
        });
        helpers.setupItemsNavigator(navigator, config);
        this.keyNavigators.push(navigator);
      });
      return this;
    },
    getNavigators() {
      return this.keyNavigators;
    },
    destroy() {
      this.keyNavigators.forEach(navigator => navigator.destroy());
      this.keyNavigators = [];
      return this;
    }
  };
  return rubricsNavigation;
});
