define('taoQtiTest/runner/plugins/controls/timer/strategy/guidedNavigation',[],function () {
  'use strict';
  function guidedNavigationStrategy(testRunner, timer) {
    var testRunnerOptions = testRunner.getOptions();
    var testPart = testRunner.getCurrentPart();
    if (timer && timer.type === 'locked' && timer.scope === 'item' && testRunnerOptions.guidedNavigation === true && testPart && testPart.isLinear) {
      return {
        name: 'guidedNavigation',
        setUp: function setUp() {
          testRunner.trigger('hidenav');
        },
        complete: function complete() {
          testRunner.trigger('disableitem disablenav shownav');
          setTimeout(function () {
            testRunner.trigger('move', 'next', 'item');
          }, 500);
        }
      };
    }
    return false;
  }
  return guidedNavigationStrategy;
});
