define('taoQtiTest/runner/plugins/security/disableRightClick',['taoTests/runner/plugin'], function (pluginFactory) {
  'use strict';

  pluginFactory = pluginFactory && Object.prototype.hasOwnProperty.call(pluginFactory, 'default') ? pluginFactory['default'] : pluginFactory;
  var disableRightClick = pluginFactory({
    name: 'disableRightClick',
    init: function init() {
      var rightClickEvents = ['contextmenu', 'mousedown', 'mouseup'];
      rightClickEvents.forEach(function (eventName) {
        window.document.addEventListener(eventName, function disableRightClick(event) {
          if (event.button === 2) {
            event.preventDefault();
          }
        });
      });
    }
  });
  return disableRightClick;
});
