define('taoQtiTest/runner/plugins/tools/apipTextToSpeech/ttsApipDataProvider',[],function () {
  'use strict';
  var getTTSItemData = apipElement => {
    var {
      identifier
    } = apipElement['@attributes'];
    var {
      contentLinkInfo = {
        '@attributes': {}
      },
      relatedElementInfo: {
        spoken: {
          audioFileInfo = []
        } = {}
      } = {}
    } = apipElement;
    var {
      fileHref = ''
    } = audioFileInfo.find(audioFile => audioFile['@attributes'].mimeType === 'audio/mpeg') || {};
    var elementId = contentLinkInfo['@attributes'].qtiLinkIdentifierRef;
    return {
      identifier,
      selector: elementId && "#".concat(elementId),
      url: fileHref.replace('assets/', '')
    };
  };
  var getTTSItemOrder = (identifier, elementOrder) => {
    var {
      order
    } = elementOrder.find(apipElementOrder => apipElementOrder['@attributes'].identifierRef === identifier) || {};
    return parseInt(order) || Number.POSITIVE_INFINITY;
  };
  var ttsApipDataProvider = apipData => {
    var {
      accessibilityInfo: {
        accessElement = []
      } = {},
      inclusionOrder: {
        textGraphicsDefaultOrder: {
          elementOrder = []
        } = {}
      } = {}
    } = apipData;
    return accessElement.map(getTTSItemData).filter(_ref => {
      var {
        url
      } = _ref;
      return !!url;
    }).sort((a, b) => getTTSItemOrder(a.identifier, elementOrder) - getTTSItemOrder(b.identifier, elementOrder));
  };
  return ttsApipDataProvider;
});
