define('taoQtiTest/runner/plugins/content/accessibility/keyNavigation/strategies/stimulusNavigation',['jquery', 'i18n', 'ui/keyNavigation/navigator', 'ui/keyNavigation/navigableDomElement', 'taoQtiTest/runner/plugins/content/accessibility/keyNavigation/helpers'], function ($, __, keyNavigator, navigableDomElement, helpers) {
  'use strict';

  $ = $ && Object.prototype.hasOwnProperty.call($, 'default') ? $['default'] : $;
  __ = __ && Object.prototype.hasOwnProperty.call(__, 'default') ? __['default'] : __;
  keyNavigator = keyNavigator && Object.prototype.hasOwnProperty.call(keyNavigator, 'default') ? keyNavigator['default'] : keyNavigator;
  navigableDomElement = navigableDomElement && Object.prototype.hasOwnProperty.call(navigableDomElement, 'default') ? navigableDomElement['default'] : navigableDomElement;
  var groupId = 'stimulus-element-navigation-group';
  var stimulusNavigation = {
    name: 'stimulus',
    init() {
      var config = this.getConfig();
      var $content = this.getTestRunner().getAreaBroker().getContentArea();
      this.keyNavigators = [];
      var isEnabledDecorator = element => {
        var originalIsEnabled = element.isEnabled;
        element.isEnabled = function isEnabled() {
          if (originalIsEnabled.call(this)) {
            var node = this.getElement().get(0);
            return node.scrollHeight > node.clientHeight;
          }
          return false;
        };
        return element;
      };
      $content.find('.stimulus-container').addClass('key-navigation-scrollable').each((i, el) => {
        var $element = $(el);
        var elements = navigableDomElement.createFromDoms($element).map(isEnabledDecorator);
        $element.attr('aria-label', __('Passage'));
        var navigator = keyNavigator({
          id: "".concat(groupId, "-").concat(i),
          elements,
          group: $element,
          propagateTab: false
        });
        helpers.setupItemsNavigator(navigator, config);
        this.keyNavigators.push(navigator);
      });
      return this;
    },
    getNavigators() {
      return this.keyNavigators;
    },
    destroy() {
      this.keyNavigators.forEach(navigator => navigator.destroy());
      this.keyNavigators = [];
      return this;
    }
  };
  return stimulusNavigation;
});
