define('taoQtiTest/runner/plugins/content/accessibility/keyNavigation/strategiesManager',['core/providerRegistry', 'taoQtiTest/runner/plugins/content/accessibility/keyNavigation/strategies/index'], function (providerRegistry, strategies) {
  'use strict';

  providerRegistry = providerRegistry && Object.prototype.hasOwnProperty.call(providerRegistry, 'default') ? providerRegistry['default'] : providerRegistry;
  function strategyFactory(name, testRunner, config) {
    var strategy = strategyFactory.getProvider(name);
    return {
      init() {
        strategy.init.call(this);
        return this;
      },
      getName() {
        return name;
      },
      getConfig() {
        return config;
      },
      getTestRunner() {
        return testRunner;
      },
      getNavigators() {
        if ('function' === typeof strategy.getNavigators) {
          return strategy.getNavigators.call(this);
        }
        return [];
      },
      destroy() {
        if ('function' === typeof strategy.destroy) {
          strategy.destroy.call(this);
        }
        return this;
      }
    };
  }
  providerRegistry(strategyFactory);
  Object.values(strategies).forEach(strategy => strategyFactory.registerProvider(strategy.name, strategy));
  return strategyFactory;
});
